interface.signature:
interface LoggerService {
  log(message: string, context?: any): void;
  error(message: string, trace?: string, context?: any): void;
  warn(message: string, context?: any): void;
  debug(message: string, context?: any): void;
  verbose(message: string, context?: any): void;
}

interface LogEntry {
  timestamp: string;          // ISO 8601 format
  level: 'debug' | 'info' | 'warn' | 'error';
  message: string;
  context?: {
    module?: string;          // Service/Controller name
    method?: string;          // Method name
    requestId?: string;       // UUID
    userId?: string;          // Authenticated user ID
    domainId?: string;        // Multi-tenant domain ID
    [key: string]: any;       // Additional context
  };
  stack?: string;             // Error stack trace (only for errors)
}

winston.createLogger({
  level: string,                    // Log level: 'debug' | 'info' | 'warn' | 'error'
  format: winston.Logform.Format,   // Log format (JSON, printf, etc.)
  transports: winston.transport[]   // Array of transports (Console, File, etc.)
}): winston.Logger
